class Solution {
    public int countDigitOne(int n) {
        int count = 0;
        long power = 1;
        for (int i = 0; i <= 9; i++) {
            long divisor = power * 10;
            long higher = n / divisor;
            long current = (n / power) % 10;
            long lower = n % power;

            if (current > 1) {
                count += (higher + 1) * power;
            } else if (current == 1) {
                count += higher * power + (lower + 1);
            } else {
                count += higher * power;
            }
            power *= 10;
        }
        return count;
    }
}

